function MenuItem({
  label,
  icon,
  testId,
  onClick,
  disabled,
  tooltip,
}: {
  label: string;
  icon: keyof typeof Icons;
  testId: string;
  onClick: () => void;
  disabled?: boolean;
  tooltip?: string;
}): JSX.Element {
  const Icon = Icons[icon];
