  const panelMat = makeRailingMaterial(railing, 'panel', elementsById, paint, {
    roughness: 0.04,
    metalness: 0,
    opacity: 0.34,
    transparent: true,
  });
  const cableMat = makeRailingMaterial(railing, 'cable', elementsById, paint, {
    roughness: 0.28,
    metalness: 0.8,
  });

